from __future__ import annotations

import json
import logging

from channels.generic.websocket import AsyncWebsocketConsumer

logger = logging.getLogger(__name__)


class ChatConsumer(AsyncWebsocketConsumer):
    async def connect(self):
        await self.accept()

    async def disconnect(self, close_code):
        pass

    async def receive(self, text_data):
        data = json.loads(text_data)
        message = data.get("message", "").strip()
        if not message:
            return

        ollama_host = self.get_ollama_host()
        ollama_model = self.get_ollama_model()

        try:
            from ollama import AsyncClient

            client = AsyncClient(host=ollama_host)
            async for part in await client.chat(
                model=ollama_model,
                messages=[{"role": "user", "content": message}],
                stream=True,
            ):
                token = part.get("message", {}).get("content", "")
                if token:
                    await self.send(
                        text_data=json.dumps(
                            {
                                "type": "token",
                                "content": token,
                            }
                        )
                    )
        except Exception as e:
            logger.exception("Ollama streaming failed")
            await self.send(
                text_data=json.dumps(
                    {
                        "type": "error",
                        "content": f"Error: {e}",
                    }
                )
            )
            return

        await self.send(text_data=json.dumps({"type": "done"}))

    def get_ollama_host(self) -> str:
        from django.conf import settings

        if hasattr(settings, "OLLAMA_HOST"):
            return settings.OLLAMA_HOST
        import os

        return os.environ.get("OLLAMA_HOST", "http://localhost:11434")

    def get_ollama_model(self) -> str:
        from django.conf import settings

        if hasattr(settings, "OLLAMA_MODEL"):
            return settings.OLLAMA_MODEL
        import os

        return os.environ.get("OLLAMA_MODEL", "qwen2.5:7b")

