<script>
  function chatApp() {
    return {
      ws: null,
      init() {
        const protocol = window.location.protocol === 'https:' ? 'wss:' : 'ws:';
        const wsUrl = protocol + '//' + window.location.host + '/ws/chat/';
        this.ws = new WebSocket(wsUrl);
        const messagesDiv = document.getElementById('messages');
        const form = document.getElementById('chat-form');
        const input = document.getElementById('message-input');

        this.ws.onmessage = function(e) {
          const data = JSON.parse(e.data);
          if (data.type === 'token') {
            let streamingDiv = messagesDiv.querySelector('.streaming');
            if (!streamingDiv) {
              const wrapper = document.createElement('div');
              wrapper.className = 'mr-auto max-w-[80%] bg-white border border-gray-200 rounded-xl px-4 py-3 shadow-sm';
              wrapper.innerHTML = '<p class="text-sm whitespace-pre-wrap"></p>';
              wrapper.classList.add('streaming');
              messagesDiv.appendChild(wrapper);
            }
            const p = messagesDiv.querySelector('.streaming p');
            p.textContent += data.content;
            messagesDiv.scrollTop = messagesDiv.scrollHeight;
          } else if (data.type === 'done') {
            const el = messagesDiv.querySelector('.streaming');
            if (el) el.classList.remove('streaming');
          } else if (data.type === 'error') {
            const existing = messagesDiv.querySelector('.streaming');
            if (existing) {
              const p = existing.querySelector('p');
              p.textContent += '\n\n' + data.content;
              existing.classList.remove('streaming');
            } else {
              const wrapper = document.createElement('div');
              wrapper.className = 'mr-auto max-w-[80%] bg-red-50 border border-red-200 rounded-xl px-4 py-3 shadow-sm';
              wrapper.innerHTML = '<p class="text-sm text-red-700 whitespace-pre-wrap">' + data.content + '</p>';
              messagesDiv.appendChild(wrapper);
            }
            messagesDiv.scrollTop = messagesDiv.scrollHeight;
          }
        };

        form.addEventListener('submit', function(e) {
          e.preventDefault();
          const msg = input.value.trim();
          if (!msg) return;
          input.value = '';
          const wrapper = document.createElement('div');
          wrapper.className = 'ml-auto max-w-[80%] bg-blue-600 text-white rounded-xl px-4 py-3 shadow-sm';
          wrapper.innerHTML = '<p class="text-sm whitespace-pre-wrap">' + msg.replace(/</g, '&lt;').replace(/>/g, '&gt;') + '</p>';
          messagesDiv.appendChild(wrapper);
          messagesDiv.scrollTop = messagesDiv.scrollHeight;
          const welcome = messagesDiv.querySelector('.flex.justify-center');
          if (welcome) welcome.remove();
          if (chatApp().ws && chatApp().ws.readyState === WebSocket.OPEN) {
            chatApp().ws.send(JSON.stringify({ message: msg }));
          }
        });
      }
    };
  }
</script>

